        assertEquals("予期される処理結果", expectedResult, result);
    }

    @Test
    public void testServiceIntegration() {
        // サービス統合のテスト
        Response response = mockService.execute(request);
        assertTrue("レスポンスは成功すべき", response.isSuccess());
    }

    @Test(expected = InvalidInputException.class)
    public void testInvalidInput() {
        // 無効な入力のテスト
        testData.process(invalidInput);
    }

    @Test
    public void testServiceFailure() {
        // サービス障害のテスト
        mockService.setFailureMode(true);
        Response response = mockService.execute(request);
        assertFalse("障害モードでは失敗すべき", response.isSuccess());
    }

    @After
    public void tearDown() throws Exception {
        // テストリソースのクリーンアップ
        if (testData != null) {
            testData.cleanup();
        }
    }
}
